            if n != 0:
                tot *= n
            else:
                zeros += 1
        if zeros &gt; 1:
            return [0] * len(nums)
        elif zeros == 1:
            ans = [0] * len(nums)
            for i in range(len(nums)):
                if nums[i] == 0:
                    ans[i] = tot
        else:
            for i in range(len(nums)):
                ans.append(tot // nums[i])

        return ans
