    public int[] productExceptSelf(int[] nums) {
        int tot = 1;
        int zeros = 0;
        int[] ans = new int[nums.length]; // initialized with 0s by default

        for (int n : nums) {
            if (n != 0) { 
                tot *= n;
            }
            else {
                zeros++;
            }
        }

        if (zeros &gt; 1) {
            return ans;
        }
        else if (zeros == 1) {
            for (int i = 0; i &lt; nums.length; i++) {
                if (nums[i] == 0) {
                    ans[i] = tot;
                }
            }
        } else {
            for (int i = 0; i &lt; nums.length; i++) {
                ans[i] = tot / nums[i];
            }
        }
        return ans;
    }
}  
