    def isPalindrome(self, s: str) -&gt; bool:
        left, right = 0, len(s) - 1

        while left &lt; right:
            if not self.isAlphanumeric(s[left]):
                left += 1
                continue

            if not self.isAlphanumeric(s[right]):
                right -= 1
                continue

            if s[left].lower() != s[right].lower():
                return False
            left += 1
            right -= 1
        return True
